create extension if not exists pgcrypto;
create table public.products (id text primary key, name text not null, description text not null, price integer not null check (price >= 0), category text not null, sizes text[] not null default '{}', stock integer not null default 0 check (stock >= 0), image_url text not null, active boolean not null default true, created_at timestamptz not null default now());
create table public.customers (id uuid primary key default gen_random_uuid(), user_id uuid unique references auth.users(id) on delete set null, name text not null, email text not null, phone text not null, address text not null, city text not null, postal_code text not null, created_at timestamptz not null default now());
create table public.orders (id text primary key, customer_id uuid not null references public.customers(id), transaction_code text unique not null, subtotal integer not null, shipping integer not null, total integer not null, status text not null check (status in ('awaiting_payment','payment_submitted','approved','rejected','completed')), created_at timestamptz not null default now());
create table public.order_items (id uuid primary key default gen_random_uuid(), order_id text not null references public.orders(id) on delete cascade, product_id text not null references public.products(id), size text not null, quantity integer not null check (quantity > 0), unit_price integer not null);
alter table public.products enable row level security; alter table public.customers enable row level security; alter table public.orders enable row level security; alter table public.order_items enable row level security;
create policy "public product catalog" on public.products for select using (active = true);
create policy "customers view own records" on public.customers for select using (auth.uid() = user_id);
create policy "customers view own orders" on public.orders for select using (customer_id in (select id from public.customers where user_id = auth.uid()));
create policy "customers view own items" on public.order_items for select using (order_id in (select id from public.orders where customer_id in (select id from public.customers where user_id = auth.uid())));
